# ===== #96: provenance clock/datetime fuzzing =====
import datetime as _dt
from assay_engine.provenance import ProvenanceTrail, ProvenanceError

UTC = _dt.timezone.utc

def attempt(name, clock):
    t = ProvenanceTrail(clock=clock)
    try:
        t.record("k", "s", x=1)
        print(f"[{name}] RECORDED OK ->", t.entries[-1].timestamp)
    except ProvenanceError as e:
        print(f"[{name}] ProvenanceError (typed): {e}")
    except BaseException as e:
        print(f"[{name}] *** RAW LEAK *** {type(e).__name__}: {e}")

# 1. clock raises ordinary Exception
attempt("ValueError", lambda: (_ for _ in ()).throw(ValueError("boom")))
# 2. clock raises BaseException (KeyboardInterrupt)
def ki():
    raise KeyboardInterrupt("interrupt")
attempt("KeyboardInterrupt", ki)
# 3. clock raises SystemExit
def se():
    raise SystemExit(3)
attempt("SystemExit", se)
# 4. clock returns non-datetime
attempt("non-datetime", lambda: "not a datetime")
# 5. clock returns naive datetime
attempt("naive", lambda: _dt.datetime(2026,1,1,0,0,0))

# 6. datetime subclass that raises in utcoffset
class BadOffset(_dt.datetime):
    def utcoffset(self):
        raise RuntimeError("offset boom")
attempt("utcoffset-raises", lambda: BadOffset(2026,1,1,tzinfo=UTC))

# 7. datetime subclass raising in astimezone
class BadAstz(_dt.datetime):
    def astimezone(self, tz=None):
        raise RuntimeError("astimezone boom")
attempt("astimezone-raises", lambda: BadAstz(2026,1,1,tzinfo=UTC))

# 8. datetime subclass raising in isoformat
class BadIso(_dt.datetime):
    def isoformat(self, *a, **k):
        raise RuntimeError("isoformat boom")
attempt("isoformat-raises", lambda: BadIso(2026,1,1,tzinfo=UTC))

# 9. datetime subclass raising BaseException in isoformat
class BadIsoBase(_dt.datetime):
    def isoformat(self, *a, **k):
        raise KeyboardInterrupt("iso interrupt")
attempt("isoformat-raises-BaseException", lambda: BadIsoBase(2026,1,1,tzinfo=UTC))

# 10. tzinfo property raises
class BadTz(_dt.datetime):
    @property
    def tzinfo(self):
        raise RuntimeError("tzinfo boom")
attempt("tzinfo-raises", lambda: BadTz(2026,1,1))

# 11. far-future / max datetime
attempt("max", lambda: _dt.datetime.max.replace(tzinfo=UTC))
attempt("min", lambda: _dt.datetime.min.replace(tzinfo=UTC))

# 12. astimezone returns something whose isoformat raises (chained subclass)
class WeirdAstz(_dt.datetime):
    def astimezone(self, tz=None):
        return BadIso(2026,1,1,tzinfo=UTC)
attempt("astimezone-returns-bad-iso", lambda: WeirdAstz(2026,1,1,tzinfo=UTC))
