# ===== #95: claim materialization, gated == scored =====
import datetime as _dt
from dataclasses import replace
from pathlib import Path
import tempfile
from assay_engine.contracts.claims import ClaimRecord
from assay_engine.contracts.study import StudyMode
from assay_engine.orchestration.gates import GateDecision
from assay_engine.pipeline import run_study
from tests import reference_study as ref

ADJUDICATE = frozenset({StudyMode.ADJUDICATE_EXTERNAL_CLAIMS})
tmp = Path(tempfile.mkdtemp())
src = ref.write_source(tmp / "c.json")

def run_with_source(name, source_obj):
    plan = ref.make_plan(src, modes=ADJUDICATE)
    plan = replace(plan, definition=replace(plan.definition, claims_source=source_obj))
    gated = {}
    def handler(review):
        gated["ids"] = list(review.payload["claim_ids"])
        gated["n"] = review.payload["n_claims"]
        return GateDecision(approved=True, gate=review.gate, reason="ok")
    try:
        res = run_study(plan, gate_handler=handler)
        scored = [v.hypothesis_id for v in res.scorecard.verdicts]
        print(f"[{name}] gated_ids={gated.get('ids')} n={gated.get('n')} scored={scored}")
        # invariant: scored hypothesis ids must correspond exactly to gated claim ids
        expect = [f"H-{c}" for c in gated["ids"]]
        if scored != expect:
            print(f"   *** DIVERGENCE *** scored {scored} != gated-derived {expect}")
    except Exception as e:
        print(f"[{name}] raised {type(e).__name__}: {e}")

# 1. Generator-based claims() that yields different objects each call
class GenSource:
    def __init__(self): self.n = 0
    def claims(self):
        self.n += 1
        base = "g1" if self.n == 1 else f"g{self.n}"
        def gen():
            yield ClaimRecord(claim_id=base, subject=base, referents=(base,), assertion={"x":1})
        return gen()
    def claim_fingerprint(self): return "fp"
run_with_source("generator-varies-each-call", GenSource())

# 2. Source yielding duplicates
class DupSource:
    def claims(self):
        return [ClaimRecord(claim_id="d1", subject="d1", referents=("d1",), assertion={"x":1}),
                ClaimRecord(claim_id="d1", subject="d1", referents=("d1",), assertion={"x":1})]
    def claim_fingerprint(self): return "fp"
run_with_source("duplicates", DupSource())

# 3. Source returning a one-shot generator (consumed by gating?) — would scoring see empty?
class OneShotGen:
    def claims(self):
        def gen():
            for c in ("o1","o2"):
                yield ClaimRecord(claim_id=c, subject=c, referents=(c,), assertion={"x":1})
        return gen()
    def claim_fingerprint(self): return "fp"
run_with_source("one-shot-generator", OneShotGen())

# 4. Source whose claims() returns different OBJECTS but same ids each call
class SameIdDiffObj:
    def claims(self):
        return [ClaimRecord(claim_id="s1", subject="s1", referents=("s1",), assertion={"x":1})]
    def claim_fingerprint(self): return "fp"
run_with_source("same-id-fresh-objects", SameIdDiffObj())
